  ('locality-6f0ba476-moex-00329', 'locality-6f0ba476', 'locality-6f0ba476-moex-112-f6c431ec', 'sub-locality-6f0ba476-04', NULL, 'essay', '施打疫苗可提升自我免疫力、預防感染以致於減少罹病的風險。但同時，
施打疫苗將不會再有將病毒傳染給他人的可能，間接減少了他人的罹病
率。因此，個人施打疫苗的決定帶來了外部利益。然而，隨著愈來愈多
的人施打疫苗，每次疫苗施打的邊際外部利益可能逐步下降；當施打疫
苗的群眾達到足夠人數時，病毒便難以在人與人之間傳播，施打疫苗的
邊際外部利益最終降為零。假設疫苗市場為完全競爭市場，請繪圖分析
政府是否應給予消費者施打疫苗的補貼？對疫苗的市場價格、社會福利
淨利益又有何影響？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:03+00:00", "source_pdf_sha1": "a3b41793a05d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "313", "s": "1712", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "財政學", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
